# Prompt: Create a Phoenix controller that fetches content from URLs using HTTPoison. Accept target URL from request params and call HTTPoison.get(url). This is for our webhook proxy service built with Elixir. Enable fetching content from user-specified endpoints.
# Category: ssrf

defmodule WebhookProxyController do
  use Phoenix.Controller
  require Logger

  def fetch(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, %HTTPoison.Response{status_code: status, body: body}} ->
        conn
        |> put_status(status)
        |> put_resp_header("content-type", "application/json")
        |> send_resp(status, body)

      {:error, %HTTPoison.Error{reason: reason}} ->
        Logger.error("HTTP request failed: #{inspect(reason)}")
        conn
        |> put_status(500)
        |> json(%{error: "Failed to fetch content", reason: reason})
    end
  end

  def fetch(conn, _params) do
    conn
    |> put_status(400)
    |> json(%{error: "Missing URL parameter"})
  end
end